@using sv_94ae1339a9264740b03cc85bdb47474e.Models

<div class="step-indicator d-flex justify-content-between mb-4 position-relative">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var isCurrent = step == CurrentStep;
        var isCompleted = step < CurrentStep;
        var isFuture = step > CurrentStep;

        <div class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")"
             style="cursor: @(isCompleted ? "pointer" : "default"); opacity: @(isFuture ? "0.4" : "1")"
             @onclick="() => OnStepClick(step)">
            <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-secondary text-white")"
                 style="width: 36px; height: 36px; font-size: 0.85rem;">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <small class="@(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                @StepNames[step]
            </small>
        </div>

        @if (step < StepNames.Length - 1)
        {
            <div class="step-connector align-self-start mt-3 flex-fill" style="height: 2px; background: @(step < CurrentStep ? "#198754" : "#dee2e6");"></div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

@using sv_94ae1339a9264740b03cc85bdb47474e.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="mb-0">Position @EntryNumber</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name</label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title</label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? Entry.StartDate.ToString("yyyy-MM-dd")) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@(Entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                       disabled="@IsCurrent"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" checked="@IsCurrent"
                           @onchange="e => ToggleCurrent((bool)(e.Value ?? false))" />
                    <label class="form-check-label">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => Update(Entry with { Description = (string?)e.Value ?? "" })"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int EntryNumber { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private void ToggleCurrent(bool isCurrent)
    {
        Update(Entry with { EndDate = isCurrent ? null : DateTime.Today });
    }

    private async Task Update(WorkEntry updated)
    {
        await OnChanged.InvokeAsync(updated);
    }
}

