@using sv_94ae1339a9264740b03cc85bdb47474e.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.FullName"
               @onchange="e => UpdateModel(Model with { FullName = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")" value="@Model.Email"
               @onchange="e => UpdateModel(Model with { Email = (string?)e.Value ?? "" })" />
        @if (emailInvalid)
        {
            <div class="invalid-feedback">Please enter a valid email address.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Model.Phone"
               @onchange="e => UpdateModel(Model with { Phone = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.Address"
               @onchange="e => UpdateModel(Model with { Address = (string?)e.Value ?? "" })" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnModelChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool emailInvalid;
    private bool isValidating;

    private async Task UpdateModel(PersonalInfo updated)
    {
        emailInvalid = false;
        ErrorMessage = null;
        await OnModelChanged.InvokeAsync(updated);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        emailInvalid = false;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            isValidating = true;
            StateHasChanged();
            try
            {
                var valid = await ValidateEmail(Model.Email);
                if (!valid)
                {
                    emailInvalid = true;
                    ErrorMessage = "The email address could not be validated.";
                    return;
                }
            }
            finally
            {
                isValidating = false;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_94ae1339a9264740b03cc85bdb47474e.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="@Entries[index]"
                   EntryNumber="@(index + 1)"
                   ShowRemove="@(Entries.Count > 1)"
                   OnChanged="entry => UpdateEntry(index, entry)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = default!;
    [Parameter] public EventCallback<List<WorkEntry>> OnEntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task UpdateEntry(int index, WorkEntry updated)
    {
        var list = new List<WorkEntry>(Entries);
        list[index] = updated;
