@using sv_94ae1339a9264740b03cc85bdb47474e.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="@References[index]"
                   ReferenceNumber="@(index + 1)"
                   ShowRemove="@(References.Count > 2)"
                   OnChanged="r => UpdateReference(index, r)"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter] public EventCallback<List<Reference>> OnReferencesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task UpdateReference(int index, Reference updated)
    {
        var list = new List<Reference>(References);
        list[index] = updated;
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task RemoveReference(int index)
    {
        var list = new List<Reference>(References);
        list.RemoveAt(index);
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<Reference>(References)
        {
            new("", "", "", "")
        };
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "Please provide at least 2 references.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                ErrorMessage = "Each reference must have at least a name and email.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

