@page "/apply"
@using sv_94ae1339a9264740b03cc85bdb47474e.Components.Apply
@using sv_94ae1339a9264740b03cc85bdb47474e.Models
@using sv_94ae1339a9264740b03cc85bdb47474e.Services
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep" OnStepSelected="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="@personalInfo"
                              OnModelChanged="p => personalInfo = p"
                              OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;

        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             OnEntriesChanged="e => workEntries = e"
                             OnNext="NextStep"
                             OnBack="PrevStep" />
            break;

        case 2:
            <ReferencesStep References="@references"
                            OnReferencesChanged="r => references = r"
                            OnNext="NextStep"
                            OnBack="PrevStep" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnCoverLetterChanged="c => coverLetter = c"
                             OnNext="NextStep"
                             OnBack="PrevStep" />
            break;

        case 4:
            <ReviewStep Personal="@personalInfo"
                        WorkEntries="@workEntries"
                        References="@references"
                        CoverLetter="@coverLetter"
                        Submitted="@submitted"
                        ApplicationId="@applicationId"
                        OnBack="PrevStep"
                        OnEditStep="GoToStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;
    private bool submitted;
    private int applicationId;

    private PersonalInfo personalInfo = new("", "", "", "");
    private List<WorkEntry> workEntries = [new("", "", DateTime.Today, null, "")];
    private List<Reference> references = [new("", "", "", ""), new("", "", "", "")];
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, 4);
    private void PrevStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = step;

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo,
            new WorkHistory(workEntries),
            references,
            coverLetter);

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        submitted = true;
    }
}

